							fabushijianChart2.setOption(option);
							  //根据窗口的大小变动图表
							window.onresize = function() {
								fabushijianChart2.resize();
							};
						}
					})
				})
			},
		init () {
			this.sfshOptions = "是,否,待审核".split(',');
		},
		indexMethod(index) {
			return (this.pageIndex - 1) * this.pageSize + index + 1;
		},
		search() {
				this.pageIndex = 1;
				this.getDataList();
			},

			// 获取数据列表
			getDataList() {
				this.dataListLoading = true;
			let params = {
				page: this.pageIndex,
				limit: this.pageSize,
				sort: 'id',
				order: 'desc',
				leixing: '技能',
				sfsh: '是',
			}
			if(this.searchForm.xuqiubiaoti!='' && this.searchForm.xuqiubiaoti!=undefined){
				params['xuqiubiaoti'] = '%' + this.searchForm.xuqiubiaoti + '%'
			}
			if(this.searchForm.yonghuxingming!='' && this.searchForm.yonghuxingming!=undefined){
				params['yonghuxingming'] = '%' + this.searchForm.yonghuxingming + '%'
			}
				let user = JSON.parse(this.$storage.getObj('userForm'))
				this.$http({
					url: "jinengxuqiu/page",
					method: "get",
					params: params
				}).then(({ data }) => {
					if (data && data.code === 0) {
						this.dataList = data.data.list;
						this.totalPage = data.data.total;
					} else {
						this.dataList = [];
						this.totalPage = 0;
					}
					this.dataListLoading = false;
				});
			},
			// 每页数
			sizeChangeHandle(val) {
				this.pageSize = val;
				this.pageIndex = 1;
				this.getDataList();
			},
			// 当前页
			currentChangeHandle(val) {
				this.pageIndex = val;
				this.getDataList();
			},
			// 多选
			selectionChangeHandler(val) {
				this.dataListSelections = val;
			},
			// 添加/修改
			addOrUpdateHandler(id,type) {
				this.showFlag = false;
				this.addOrUpdateFlag = true;
				this.crossAddOrUpdateFlag = false;
				if(type!='info'&&type!='msg'){
					type = 'else';
				}
				this.$nextTick(() => {
					this.$refs.addOrUpdate.init(id,type );
				});
			},
			// 查看评论
			disscussListHandler(id,type) {
				this.$router.push({path:'/discussjinengxuqiu',query:{refid:id}});
			},
			//批量审核窗口
			shBatchDialog(){
				for(let x in this.dataListSelections){
					if(this.dataListSelections[x].sfsh&&this.dataListSelections[x].sfsh!='待审核'){
						this.$message.error('存在已审核数据，不能继续操作');
						this.batchIds = []
						return false
					}
					this.batchIds.push(this.dataListSelections[x].id)
				}
				this.shList = this.dataListSelections
				this.sfshBatchVisiable = true
			},
			//批量审核
			shBatchHandler(){
				this.$refs["shBatchForm"].validate(valid => {
					if(valid){
						this.$confirm(`是否${this.batchIds.length>1?'一键审核':'审核'}选中数据?`, "提示", {
							confirmButtonText: "确定",
							cancelButtonText: "取消",
							type: "warning"
						}).then(async() => {
							this.$http({
								url: "jinengxuqiu/shBatch?sfsh="+this.shBatchForm.sfsh+"&shhf="+this.shBatchForm.shhf,
								method: "post",
								data: this.batchIds
							}).then(async ({ data }) => {
								if (data && data.code === 0) {
									this.$message({
										message: "操作成功",
										type: "success",
										duration: 1500,
										onClose: () => {
											this.getDataList();
											this.sfshBatchVisiable = false
											this.batchIds = []
										}
									});
								} else {
									this.$message.error(data.msg);
								}
							});
						});
					}
				})
			},
			// 查看详情
			viewDetail(row) {
				this.detailData = row;
				this.showFlag = false;
				this.detailFlag = true;
			},
			closeDetail() {
				this.detailFlag = false;
				this.showFlag = true;
			},
			// 删除（带交换检查）
			async deleteWithCheck(row) {
				try {
					const { data } = await this.$http({
						url: 'jiaohuanshenqing/page',
						method: 'get',
						params: { page: 1, limit: 1, xuqiubianhao: row.xuqiubianhao }
					});
					if (data && data.code === 0 && data.data.list && data.data.list.length > 0) {
						this.$message.error('该技能已参与技能交换，无法删除');
						return;
					}
					this.deleteHandler(row.id);
				} catch(e) {
					this.deleteHandler(row.id);
				}
			},
			// 删除
			async deleteHandler(id ) {
				var ids = id? [Number(id)]: this.dataListSelections.map(item => {
					return Number(item.id);
				});
				await this.$confirm(`确定进行[${id ? "删除" : "批量删除"}]操作?`, "提示", {
					confirmButtonText: "确定",
					cancelButtonText: "取消",
					type: "warning"
				}).then(async () => {
					await this.$http({
						url: "jinengxuqiu/delete",
						method: "post",
						data: ids
					}).then(async ({ data }) => {
						if (data && data.code === 0) {
							for(let x in ids){
								await this.$http.get('storeup/list',{params: {
									page: 1,
									limit: 100,
									refid: ids[x],
									tablename: 'jinengxuqiu'
								}}).then(async obj=>{
									if(obj.data&&obj.data.code==0){
										if(obj.data.data.list.length){
											let arr = []
											for(let i in obj.data.data.list){
												arr.push(obj.data.data.list[i].id)
											}
											await this.$http.post('storeup/delete',arr).then(()=>{})
										}
									}
								})
							}
							this.$message({
								message: "操作成功",
								type: "success",
								duration: 1500,
								onClose: () => {
									this.search();
								}
							});
			
						} else {
							this.$message.error(data.msg);
						}
					});
				});
			},
		}

	};
