			// 统计接口1
			chartDialog1() {
				this.$nextTick(()=>{
					var jiaohuanshijianChart1 = echarts.init(document.getElementById("jiaohuanshijianChart1"),'macarons');
					let params = {}
					this.$http({
						url: "jiaohuanjilu/group/jiaohuanshijian",
						method: "get",
						params
					}).then(({data})=>{
						if (data && data.code === 0) {
							let res = data.data;
							let xAxis = [];
							let yAxis = [];
							let pArray = []
							for(let i=0;i<res.length;i++){
								if(this.boardBase&&i==this.boardBase.pieNum){
									break;
								}
								// 统计图设置对了吗
								xAxis.push(res[i].jiaohuanshijian);
								yAxis.push(parseFloat((res[i].total)));
								pArray.push({
									value: parseFloat((res[i].total)),
									name: res[i].jiaohuanshijian
								})
							}
							var option = {};
							let titleObj = this.pie.title
							titleObj.text = '交换量统计'
							
							const legendObj = this.pie.legend
							let tooltipObj = {trigger: 'item',formatter: '{b} : {c} ({d}%)'}
							tooltipObj = Object.assign(tooltipObj , this.pie.tooltip?this.pie.tooltip:{})
							
							let seriesObj = {
								type: 'pie',
								radius: ['25%', '55%'],
								center: ['50%', '60%'],
								data: pArray,
								emphasis: {
									itemStyle: {
										shadowBlur: 10,
										shadowOffsetX: 0,
										shadowColor: 'rgba(0, 0, 0, 0.5)'
									}
								}
							}
							seriesObj = Object.assign(seriesObj , this.pie.series)
							const gridObj = this.pie.grid
							option = {
								backgroundColor: this.pie.backgroundColor,
								color: this.pie.color,
								title: titleObj,
								legend: legendObj,
								grid: gridObj,
								tooltip: tooltipObj,
								series: [seriesObj]
							};
							// 使用刚指定的配置项和数据显示图表。
							jiaohuanshijianChart1.setOption(option);
							  //根据窗口的大小变动图表
							window.onresize = function() {
								jiaohuanshijianChart1.resize();
							};
						}
					})
				})
			},
			init () {
				this.$http({
					url: `option/jinengfenlei/jinengfenlei`,
					method: "get"
				}).then(({ data }) => {
					if (data && data.code === 0) {
						this.jiaohuanjinengOptions = data.data;
					} else {
						this.$message.error(data.msg);
					}
				});
