			indexMethod(index) {
				return (this.pageIndex - 1) * this.pageSize + index + 1;
			},
			search() {
				this.pageIndex = 1;
				this.getDataList();
			},

			// 获取数据列表
			getDataList() {
				this.dataListLoading = true;
				let params = {
					page: this.pageIndex,
					limit: this.pageSize,
					sort: 'id',
					order: 'desc',
				}
				if(this.searchForm.yonghuxingming!='' && this.searchForm.yonghuxingming!=undefined){
					params['yonghuxingming'] = '%' + this.searchForm.yonghuxingming + '%'
				}
				if(this.searchForm.biaoti!='' && this.searchForm.biaoti!=undefined){
					params['biaoti'] = '%' + this.searchForm.biaoti + '%'
				}
				if(this.searchForm.jinengfenlei!='' && this.searchForm.jinengfenlei!=undefined){
					params['jinengfenlei'] = '%' + this.searchForm.jinengfenlei + '%'
				}
				if(this.searchForm.jiaohuanjineng!='' && this.searchForm.jiaohuanjineng!=undefined){
					params['jiaohuanjineng'] = this.searchForm.jiaohuanjineng
				}
				if(this.searchForm.gongjirenxingming!='' && this.searchForm.gongjirenxingming!=undefined){
					params['gongjirenxingming'] = '%' + this.searchForm.gongjirenxingming + '%'
				}
				let user = JSON.parse(this.$storage.getObj('userForm'))
				this.$http({
					url: "jiaohuanjilu/page",
					method: "get",
					params: params
				}).then(({ data }) => {
					if (data && data.code === 0) {
						this.dataList = data.data.list;
						this.totalPage = data.data.total;
					} else {
						this.dataList = [];
						this.totalPage = 0;
					}
					this.dataListLoading = false;
				});
			},
			// 每页数
			sizeChangeHandle(val) {
				this.pageSize = val;
				this.pageIndex = 1;
				this.getDataList();
			},
			// 当前页
			currentChangeHandle(val) {
				this.pageIndex = val;
				this.getDataList();
			},
			// 多选
			selectionChangeHandler(val) {
				this.dataListSelections = val;
			},
			// 添加/修改
			addOrUpdateHandler(id,type) {
				this.showFlag = false;
				this.addOrUpdateFlag = true;
				this.crossAddOrUpdateFlag = false;
				if(type!='info'&&type!='msg'){
					type = 'else';
				}
				this.$nextTick(() => {
					this.$refs.addOrUpdate.init(id,type );
				});
			},
